'use client';

import { useEffect, useState } from 'react';
import type { Project } from '@/types/project';

// Import existing components (will be migrated to TS later)
import { Analytics } from '@/lib/analytics';
import { KeyboardShortcuts } from '@/lib/keyboard';
import { Storage } from '@/lib/storage';
import { Toast } from '@/components/Toast';
import { ProjectTags } from '@/components/ProjectTags';

// Import projects data
// @ts-ignore - projects.js is a plain JS file
import projectsData from '../../projects.js';

export default function Portfolio() {
  const [mounted, setMounted] = useState(false);
  const [projects] = useState<Project[]>(projectsData);

  useEffect(() => {
    setMounted(true);

    // Initialize global instances
    if (typeof window !== 'undefined') {
      (window as any).analytics = new Analytics();
      (window as any).keyboard = new KeyboardShortcuts();
      (window as any).storage = Storage;
      (window as any).Toast = Toast;

      // Track page view
      (window as any).analytics.trackPageView();

      // Initialize enhanced features
      initializeEnhancedFeatures();
    }
  }, []);

  function initializeEnhancedFeatures() {
    // Setup keyboard shortcuts
    setupKeyboardShortcuts();

    // Setup bookmarks
    setupBookmarks();

    // Assign tags to projects
    projects.forEach((project) => {
      if (!project.tags) {
        project.tags = ProjectTags.assignTags(project);
      }
    });

    // Show welcome message
    const summary = (window as any).analytics.getSummary();
    if (summary.totalVisits === 1) {
      setTimeout(() => {
        Toast.success('Welcome to Saad Web Experiments! 👋', { duration: 5000 });
      }, 1000);
    }

    console.log('✨ Enhanced features initialized');
  }

  function setupKeyboardShortcuts() {
    const searchInput = document.getElementById('search-input') as HTMLInputElement;

    // Focus search (/)
    (window as any).keyboard.register('/', () => {
      searchInput?.focus();
      Toast.info('Search focused');
    });

    // Clear search (Escape)
    (window as any).keyboard.register('Escape', () => {
      if (searchInput?.value) {
        searchInput.value = '';
        searchInput.dispatchEvent(new Event('input'));
        Toast.info('Search cleared');
      }
    });

    // Toggle dark mode (Ctrl+D)
    (window as any).keyboard.register('d', () => {
      document.getElementById('theme-toggle')?.click();
    }, { ctrl: true });

    // Show bookmarks (Ctrl+B)
    (window as any).keyboard.register('b', () => {
      showBookmarksModal();
    }, { ctrl: true });

    // Show help (Shift+?)
    (window as any).keyboard.register('?', () => {
      showKeyboardShortcutsHelp();
    }, { shift: true });
  }

  function setupBookmarks() {
    (window as any).bookmarks = {
      add: (projectId: string, projectTitle: string) => {
        const bookmarks = (window as any).storage.get('bookmarks', []);
        if (!bookmarks.find((b: any) => b.id === projectId)) {
          bookmarks.push({ id: projectId, title: projectTitle, timestamp: Date.now() });
          (window as any).storage.set('bookmarks', bookmarks);
          Toast.success('Bookmark added');
          return true;
        }
        return false;
      },
      remove: (projectId: string) => {
        const bookmarks = (window as any).storage.get('bookmarks', []);
        const filtered = bookmarks.filter((b: any) => b.id !== projectId);
        (window as any).storage.set('bookmarks', filtered);
        Toast.info('Bookmark removed');
      },
      has: (projectId: string) => {
        const bookmarks = (window as any).storage.get('bookmarks', []);
        return bookmarks.some((b: any) => b.id === projectId);
      },
      getAll: () => (window as any).storage.get('bookmarks', []),
    };
  }

  function showBookmarksModal() {
    // Implementation from index-enhanced.html
    const bookmarks = (window as any).bookmarks.getAll();
    if (bookmarks.length === 0) {
      Toast.info('No bookmarks yet. Start bookmarking projects!');
      return;
    }
    // Modal implementation...
  }

  function showKeyboardShortcutsHelp() {
    // Implementation from index-enhanced.html
    const shortcuts = (window as any).keyboard.getAll();
    // Modal implementation...
  }

  if (!mounted) {
    return null;
  }

  return (
    <>
      <header className="site-header">
        <div className="container header-row">
          <div>
            <h1 className="site-title">Saad Web Experiments</h1>
            <p className="lead">
              <em><strong>Muhammad Saad Amin</strong></em>, a passionate <strong>Software Engineer</strong>,
              created this project during the <strong>Free Code Camp</strong> course while earning the{' '}
              <em>Responsive Web Design Certification</em>. This project includes web pages and scripts
              demonstrating principles of <strong>HTML</strong>, <strong>CSS</strong>, <strong>JavaScript</strong>,
              <strong>Python</strong>, and <strong>React</strong>.
            </p>
          </div>
          <button id="theme-toggle" className="theme-toggle" aria-label="Toggle dark mode">
            🌙
          </button>
        </div>
      </header>

      <main className="container">
        {/* Search */}
        <div className="center">
          <div className="search-bar">
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" fill="none" stroke="currentColor"
              strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <circle cx="11" cy="11" r="8"></circle>
              <line x1="21" y1="21" x2="16.65" y2="16.65"></line>
            </svg>
            <input type="text" id="search-input" placeholder="Search projects... (Press / to focus)" />
          </div>
        </div>

        {/* Filter Tabs */}
        <div className="filter-tabs" id="filter-tabs">
          <button className="filter-btn active" data-filter="All">
            <span className="filter-icon">🗂️</span> All
          </button>
          <button className="filter-btn" data-filter="HTML">
            <span className="filter-icon">🌐</span> HTML
          </button>
          <button className="filter-btn" data-filter="CSS">
            <span className="filter-icon">🎨</span> CSS
          </button>
          <button className="filter-btn" data-filter="JavaScript">
            <span className="filter-icon">⚡</span> JavaScript
          </button>
          <button className="filter-btn" data-filter="Python">
            <span className="filter-icon">🐍</span> Python
          </button>
          <button className="filter-btn" data-filter="React">
            <span className="filter-icon">⚛️</span> React
          </button>
        </div>

        {/* Project Count Badge */}
        <div className="results-meta" id="results-meta"></div>

        {/* Project Container */}
        <div id="project-container" className="grid"></div>
      </main>

      <footer className="site-footer">
        <div className="container">
          <p>© <strong>Muhammad Saad Amin</strong> — Free Code Camp Projects</p>
          <p className="footer-hint">Press <kbd>?</kbd> for keyboard shortcuts</p>
        </div>
      </footer>

      {/* Load the app.js logic */}
      <script src="/src/app.js" type="module" />
    </>
  );
}
